# Spec — v2 merge-on-read delete with a compound AND range predicate
# (delete where id >= 2 AND id < 4). Classic range DML: tests the runner's
# NewAnd lowering and that both bounds apply (inclusive lower, exclusive upper).
# Authored-golden (minted from iceberg-java).

header:
  id: v2_delete_range_and
  format-version: 2
  spec-anchor: "table-spec#row-level-deletes"
  table-uuid: "9d0e1f2a-3b4c-5d6e-7f80-912233445566"
  seeds:
    snapshot-id: sequential
    commit-ts: "2026-01-01T00:00:00Z"
    file-paths: templated
  schema:
    fields:
      - { id: 1, name: id,  type: long,   required: true }
      - { id: 2, name: val, type: string }

entries:
  - op: append
    rows:
      - { __rowkey: r1, id: !long 1, val: !string "a" }
      - { __rowkey: r2, id: !long 2, val: !string "b" }
      - { __rowkey: r3, id: !long 3, val: !string "c" }
      - { __rowkey: r4, id: !long 4, val: !string "d" }
      - { __rowkey: r5, id: !long 5, val: !string "e" }

  - op: delete
    strategy: merge-on-read
    kind: position
    predicate:
      type: and
      args:
        - { type: gt-eq, term: id, value: !long 2 }
        - { type: lt,    term: id, value: !long 4 }
    expect:
      snapshot: { operation: delete }
      delete-file: { content: 1 }

  - op: observe
    at: latest
    expect:
      scan:
        rows:
          - { id: 1, val: a }
          - { id: 4, val: d }
          - { id: 5, val: e }

# Spec — v2 two sequential merge-on-read deletes across separate commits, with a
# time-travel read of the intermediate state. Classic accumulating DML: each
# delete adds its own delete file; the live set shrinks monotonically; and the
# snapshot BETWEEN the two deletes still reads its own intermediate multiset.
# Authored-golden (minted from iceberg-java).

header:
  id: v2_multi_delete_sequence
  format-version: 2
  spec-anchor: "table-spec#row-level-deletes"
  table-uuid: "2a3b4c5d-6e7f-8091-2233-445566778899"
  seeds:
    snapshot-id: sequential
    commit-ts: "2026-01-01T00:00:00Z"
    file-paths: templated
  schema:
    fields:
      - { id: 1, name: id,  type: long,   required: true }
      - { id: 2, name: val, type: string }

entries:
  - op: append
    rows:
      - { __rowkey: r1, id: !long 1, val: !string "a" }
      - { __rowkey: r2, id: !long 2, val: !string "b" }
      - { __rowkey: r3, id: !long 3, val: !string "c" }
      - { __rowkey: r4, id: !long 4, val: !string "d" }

  - op: delete
    strategy: merge-on-read
    kind: position
    predicate: { type: eq, term: id, value: !long 1 }
    expect:
      snapshot: { operation: delete }
      delete-file: { content: 1 }

  - op: observe
    at: latest
    bind: after-first-delete
    expect:
      scan:
        rows:
          - { id: 2, val: b }
          - { id: 3, val: c }
          - { id: 4, val: d }

  - op: delete
    strategy: merge-on-read
    kind: position
    predicate: { type: eq, term: id, value: !long 3 }
    expect:
      snapshot: { operation: delete }
      delete-file: { content: 1 }

  - op: observe
    at: latest
    expect:
      scan:
        rows:
          - { id: 2, val: b }
          - { id: 4, val: d }

  # the intermediate snapshot still reads its own state (3 rows)
  - op: observe
    at: after-first-delete
    expect:
      scan:
        rows:
          - { id: 2, val: b }
          - { id: 3, val: c }
          - { id: 4, val: d }
